1	<!DOCTYPE html>
2	<html lang="ja">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=no">
6	<title>SpringSense</title>
7	<style>
8	*{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
9	html,body{height:100%;overflow:hidden}
10	body{font-family:-apple-system,'Hiragino Sans','Noto Sans JP',sans-serif;background:#EEF5F0;color:#222;display:flex;flex-direction:column}
11	
12	/* Header */
13	.header{background:linear-gradient(135deg,#1B6B3A 0%,#2DAA62 100%);color:#fff;padding:12px 16px 10px;display:flex;align-items:center;gap:10px;flex-shrink:0;box-shadow:0 2px 8px rgba(0,0,0,.2)}
14	.header-icon{width:32px;height:32px;background:rgba(255,255,255,.22);border-radius:9px;display:flex;align-items:center;justify-content:center;font-size:17px;flex-shrink:0}
15	.header-texts{flex:1}
16	.header-title{font-size:15px;font-weight:700;letter-spacing:.2px}
17	.header-sub{font-size:10px;color:rgba(255,255,255,.65);margin-top:1px}
18	.header-disclaimer{font-size:9px;color:#A8F0C0;margin-top:2px;line-height:1.3;font-weight:500}
19	.header-jis{font-size:10px;background:rgba(255,255,255,.18);border:1px solid rgba(255,255,255,.28);border-radius:10px;padding:3px 9px;white-space:nowrap;flex-shrink:0}
20	
21	/* Main */
22	.main{flex:1;overflow:hidden;display:flex;flex-direction:column;padding:10px 12px;gap:8px}
23	
24	/* Material pills */
25	.mat-row{display:flex;gap:6px;overflow-x:auto;flex-shrink:0;padding:2px 0;-webkit-overflow-scrolling:touch;scrollbar-width:none}
26	.mat-row::-webkit-scrollbar{display:none}
27	.mat-pill{border-radius:20px;padding:7px 13px;font-size:12px;font-weight:600;cursor:pointer;border:2px solid transparent;flex-shrink:0;transition:all .15s;user-select:none}
28	.mat-pill.active{background:#1B6B3A;color:#fff;border-color:#1B6B3A}
29	.mat-pill:not(.active){background:#D8EEE0;color:#1B6B3A;border-color:#A8D8B8}
30	
31	/* Result card */
32	.result-card{background:#fff;border-radius:14px;padding:12px 16px;flex-shrink:0;box-shadow:0 1px 6px rgba(0,0,0,.08)}
33	.result-badge-row{display:flex;align-items:center;justify-content:center;gap:10px;margin-bottom:8px}
34	.result-badge{font-size:22px;font-weight:800;padding:6px 20px;border-radius:24px;letter-spacing:.5px}
35	.badge-ok{background:#E8F5E9;color:#1B6B3A}
36	.badge-ng{background:#FCEBEB;color:#A32D2D}
37	.badge-warn{background:#FFF8E1;color:#7A5500}
38	.result-ratio-row{display:flex;align-items:center;gap:10px}
39	.ratio-label{font-size:11px;color:#888;white-space:nowrap}
40	.ratio-bar-bg{flex:1;height:10px;background:#E0E0E0;border-radius:5px;overflow:hidden}
41	.ratio-bar{height:100%;border-radius:5px;transition:width .4s cubic-bezier(.4,0,.2,1)}
42	.ratio-val{font-size:13px;font-weight:700;min-width:44px;text-align:right}
43	.result-hint{text-align:center;font-size:10px;color:#aaa;margin-top:5px}
44	
45	/* Param chips */
46	.chips-grid{display:grid;grid-template-columns:1fr 1fr;gap:7px;flex-shrink:0}
47	.chip{position:relative;border-radius:11px;padding:8px 10px;display:flex;align-items:center;gap:7px;cursor:pointer;overflow:hidden;min-height:52px}
48	.chip-1{background:#F0EBD8}
49	.chip-2{background:#E4EFF5}
50	.chip-3{background:#EBE8F5}
